mapper.select:
SELECT id as id, dealerId as dealerId, (select dealerName from dealer where id = dealerId) as dealerName, productId as productId, (select productName from product_config where id = productId) as productName, orderDate as orderDate, quantity as quantity, price as price, totalAmount as totalAmount, marketFee as marketFee, expectRate as expectRate FROM sale_order
1=1
AND id = #{id}
AND dealerId = #{dealerId}
AND productName LIKE CONCAT('%', #{productName}, '%')
AND quantity = #{quantity}
ORDER BY id DESC
